async (page) => {
  // Try clicking canvas at a point in the direction of Forester (north/up and slightly east)
  // Current position 191,159. Forester at 216,114 - need to go NE direction
  // Click toward top-right of visible screen to walk there
  await page.evaluate(() => {
    const canvas = document.getElementById('canvas');
    // Click towards upper portion of screen (north direction)
    canvas.dispatchEvent(new MouseEvent('click', { clientX: 800, clientY: 100, bubbles: true, ctrlKey: false }));
  });
  await page.waitForTimeout(4000);
  const pos = await page.evaluate(() => window.__latestGameState ? window.__latestGameState.player_position : null);
  return JSON.stringify(pos);
}
